<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; }
  body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Arial, sans-serif;
    margin: 0;
    padding: 20px;
    background: #f5f6f8;
    color: #222;
    line-height: 1.5;
  }
  .container {
    max-width: 900px;
    margin: 0 auto;
    display: grid;
    grid-template-columns: 320px 1fr;
    gap: 20px;
  }
  @media (max-width: 720px) {
    .container { grid-template-columns: 1fr; }
  }
  .panel {
    background: #fff;
    border: 1px solid #e3e5ea;
    border-radius: 8px;
    padding: 18px;
  }
  h1 {
    font-size: 1.4rem;
    margin: 0 0 16px;
  }
  h2 {
    font-size: 1.05rem;
    margin: 0 0 12px;
    color: #444;
  }
  label {
    display: block;
    font-size: 0.85rem;
    margin: 10px 0 4px;
    color: #555;
  }
  input, select, textarea {
    width: 100%;
    padding: 8px 10px;
    font-size: 0.95rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    background: #fff;
    font-family: inherit;
  }
  input:focus, select:focus, textarea:focus {
    outline: none;
    border-color: #3b82f6;
    box-shadow: 0 0 0 2px rgba(59,130,246,0.15);
  }
  textarea { resize: vertical; min-height: 50px; }
  button {
    cursor: pointer;
    border: none;
    border-radius: 4px;
    padding: 9px 14px;
    font-size: 0.95rem;
    font-family: inherit;
  }
  #add-expense {
    background: #2563eb;
    color: #fff;
    width: 100%;
    margin-top: 14px;
  }
  #add-expense:hover { background: #1d4ed8; }
  #form-error {
    color: #b91c1c;
    background: #fef2f2;
    border: 1px solid #fecaca;
    padding: 8px 10px;
    border-radius: 4px;
    font-size: 0.85rem;
    margin-top: 12px;
    min-height: 0;
    display: none;
  }
  #form-error:not(:empty) { display: block; }
  .filters {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 8px;
  }
  .filters label.full { grid-column: 1 / -1; }
  .summary-box {
    background: #f8fafc;
    border: 1px solid #e3e5ea;
    border-radius: 6px;
    padding: 12px;
    margin-bottom: 16px;
