    display: flex;
    justify-content: space-between;
    padding: 4px 0;
    font-size: 0.9rem;
    border-bottom: 1px dashed #e3e5ea;
  }
  .cat-total:last-child { border-bottom: none; }
  .cat-total .cat-name { text-transform: capitalize; }
  .expense-list { list-style: none; padding: 0; margin: 0; }
  .expense {
    display: grid;
    grid-template-columns: auto 1fr auto auto;
    gap: 10px;
    align-items: center;
    padding: 10px 12px;
    border: 1px solid #e3e5ea;
    border-radius: 6px;
    margin-bottom: 8px;
    background: #fff;
  }
  .expense .amt {
    font-weight: 600;
    color: #b91c1c;
    white-space: nowrap;
  }
  .expense .cat-badge {
    background: #e0e7ff;
    color: #3730a3;
    padding: 2px 8px;
    border-radius: 12px;
    font-size: 0.78rem;
    text-transform: capitalize;
  }
  .expense .meta {
    font-size: 0.85rem;
    color: #666;
  }
  .expense .note {
    font-size: 0.85rem;
    color: #444;
    font-style: italic;
  }
  .exp-del {
    background: #fee2e2;
    color: #b91c1c;
    padding: 5px 10px;
    font-size: 0.8rem;
  }
  .exp-del:hover { background: #fecaca; }
  .empty-state {
    text-align: center;
    color: #888;
    padding: 30px 10px;
    font-size: 0.9rem;
  }
</style>
</head>
<body>
<div class="container">
  <aside class="panel">
    <h1>Expense Tracker</h1>
    <form id="expense-form" novalidate>
      <label for="amount">Amount</label>
      <input type="number" id="amount" step="0.01" min="0.01" placeholder="0.00" required>

      <label for="category">Category</label>
      <select id="category" required>
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>

      <label for="date">Date</label>
      <input type="date" id="date" required>

      <label for="note">Note (optional)</label>
      <textarea id="note" placeholder="e.g. weekly groceries"></textarea>

      <button type="submit" id="add-expense">Add Expense</button>
      <div id="form-error" role="alert"></div>
    </form>
  </aside>

  <main class="panel">
    <h2>Filters</h2>
    <div class="filters">
      <label class="full" for="filter-category">Category</label>
      <select id="filter-category" class="full" style="grid-column:1 / -1">
        <option value="all">All Categories</option>
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>

      <label for="filter-from">From</label>
      <label for="filter-to">To</label>
      <input type="date" id="filter-from">
      <input type="date" id="filter-to">
    </div>

    <div class="summary-box" style="margin-top:16px">
      <div class="total-line">
        <span>Total (visible):</span>
        <span class="amount" id="total">0.00</span>
      </div>
      <div class="cat-list" id="cat-list"></div>
    </div>

    <h2 style="margin-top:18px">Expenses</h2>
    <ul class="expense-list" id="expense-list"></ul>
    <div class="empty-state" id="empty-state" style="display:none">No expenses yet. Add one to get started.</div>
  </main>
</div>

<script>
(function() {
  "use strict";

  const STORAGE_KEY = "expense-tracker-v1";
  const CATEGORIES = ["groceries", "transport", "bills", "fun"];

  let expenses = [];

  // DOM refs
  const form = document.getElementById("expense-form");
  const amountEl = document.getElementById("amount");
  const categoryEl = document.getElementById("category");
  const dateEl = document.getElementById("date");
  const noteEl = document.getElementById("note");
  const formError = document.getElementById("form-error");
  const listEl = document.getElementById("expense-list");
  const emptyState = document.getElementById("empty-state");
  const totalEl = document.getElementById("total");
  const catListEl = document.getElementById("cat-list");
  const filterCategory = document.getElementById("filter-category");
  const filterFrom = document.getElementById("filter-from");
  const filterTo = document.getElementById("filter-to");

  // ---------- Persistence ----------
  function load() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        const parsed = JSON.parse(raw);
        if (Array.isArray(parsed)) {
          expenses = parsed.filter(isValidExpense);
        }
      }
    } catch (e) {
      expenses = [];
    }
  }

  function save() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    } catch (e) { /* ignore quota errors */ }
  }

  function isValidExpense(e) {
    return e && typeof e.id !== "undefined" &&
      typeof e.amount === "number" && isFinite(e.amount) && e.amount > 0 &&
      typeof e.category === "string" && CATEGORIES.indexOf(e.category) !== -1 &&
      typeof e.date === "string" && e.date.length > 0;
  }

  // ---------- Formatting ----------
  function fmt(n) {
    return (Math.round(n * 100) / 100).toFixed(2);
  }

  function formatDate(d) {
    // d is YYYY-MM-DD; display as-is but readable
    if (!d) return "";
    const parts = d.split("-");
    if (parts.length !== 3) return d;
    return parts[1] + "/" + parts[2] + "/" + parts[0];
  }

  // ---------- Validation ----------
  function validate() {
    const rawAmount = amountEl.value;
    const amount = parseFloat(rawAmount);
    const date = dateEl.value;

    if (rawAmount === "" || rawAmount === null || isNaN(amount)) {
      return "Please enter a valid amount.";
    }
    if (amount <= 0) {
      return "Amount must be greater than zero.";
    }
    if (!date) {
      return "Please select a date.";
    }
    return "";
  }

  // ---------- Add ----------
  form.addEventListener("submit", function(e) {
    e.preventDefault();
    const err = validate();
    if (err) {
      formError.textContent = err;
      return;
    }
    formError.textContent = "";

    const expense = {
      id: Date.now() + "-" + Math.random().toString(36).slice(2, 8),
      amount: parseFloat(amountEl.value),
      category: categoryEl.value,
      date: dateEl.value,
      note: noteEl.value.trim()
    };

    expenses.unshift(expense);
    save();
    render();

    // Reset amount field only (per contract)
    amountEl.value = "";
    amountEl.focus();
  });

  // ---------- Delete ----------
  listEl.addEventListener("click", function(e) {
    const btn = e.target.closest(".exp-del");
    if (!btn) return;
    const row = btn.closest(".expense");
    if (!row) return;
    const id = row.getAttribute("data-id");
    expenses = expenses.filter(function(x) { return String(x.id) !== String(id); });
    save();
    render();
  });

  // ---------- Filters ----------
  function passesFilters(exp) {
    const cat = filterCategory.value;
    if (cat !== "all" && exp.category !== cat) return false;

    const from = filterFrom.value;
    const to = filterTo.value;
    if (from && exp.date < from) return false;
    if (to && exp.date > to) return false;
    return true;
  }

  filterCategory.addEventListener("change", render);
  filterFrom.addEventListener("change", render);
  filterTo.addEventListener("change", render);

  // ---------- Render ----------
  function render() {
    const visible = expenses.filter(passesFilters);

    // List (newest first — expenses array is already newest-first because we unshift)
    listEl.innerHTML = "";
    if (visible.length === 0) {
      emptyState.style.display = "block";
    } else {
      emptyState.style.display = "none";
      const frag = document.createDocumentFragment();
      visible.forEach(function(exp) {
        const li = document.createElement("li");
        li.className = "expense";
        li.setAttribute("data-id", exp.id);

        const amt = document.createElement("span");
        amt.className = "amt";
        amt.textContent = "$" + fmt(exp.amount);

        const info = document.createElement("div");
        info.style.minWidth = "0";

        const top = document.createElement("div");
        top.style.display = "flex";
        top.style.gap = "8px";
        top.style.alignItems = "center";
        top.style.flexWrap = "wrap";

        const badge = document.createElement("span");
        badge.className = "cat-badge";
        badge.textContent = exp.category;
        top.appendChild(badge);

        const meta = document.createElement("span");
        meta.className = "meta";
        meta.textContent = formatDate(exp.date);
        top.appendChild(meta);

        info.appendChild(top);

        if (exp.note) {
          const note = document.createElement("div");
          note.className = "note";
          note.textContent = exp.note;
          info.appendChild(note);
        }

        const del = document.createElement("button");
        del.className = "exp-del";
        del.type = "button";
        del.setAttribute("aria-label", "Delete expense");
        del.textContent = "Delete";

        li.appendChild(amt);
        li.appendChild(info);
        li.appendChild(del);
        frag.appendChild(li);
      });
      listEl.appendChild(frag);
    }

    // Total of visible
    const total = visible.reduce(function(s, e) { return s + e.amount; }, 0);
    totalEl.textContent = fmt(total);

    // Per-category summary (visible totals)
    catListEl.innerHTML = "";
    CATEGORIES.forEach(function(cat) {
      const sum = visible
        .filter(function(e) { return e.category === cat; })
        .reduce(function(s, e) { return s + e.amount; }, 0);
      const div = document.createElement("div");
      div.className = "cat-total";
      div.setAttribute("data-cat", cat);
      const name = document.createElement("span");
      name.className = "cat-name";
      name.textContent = cat;
      const val = document.createElement("span");
      val.textContent = "$" + fmt(sum);
      div.appendChild(name);
      div.appendChild(val);
      catListEl.appendChild(div);
    });
  }

  // ---------- Init ----------
  load();
  // Default date to today
  const today = new Date();
  const yyyy = today.getFullYear();
  const mm = String(today.getMonth() + 1).padStart(2, "0");
  const dd = String(today.getDate()).padStart(2, "0");
  dateEl.value = yyyy + "-" + mm + "-" + dd;
  render();
})();
</script>
</body>
</html>
